<html>
<head>
<meta charset="utf-8">
<title>jnxweb</title>
<style>
  :root { color-scheme: light dark; }
  * { box-sizing: border-box; }
  body {
    margin: 0; padding: 12px;
    font-family: Menlo, Consolas, "Courier New", monospace;
    font-size: 13px;
    background: #111; color: #ddd;
  }
